queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?era_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasEras ?child ; p:hasCostume_Designers ?parent . } GROUP BY ?child }
  ?child p:era_name ?era_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Costume_Designers } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?era_name WHERE {
  ?costume_designers_eras a :Costume_Designers_Eras .
  ?eras a :Eras .
  ?costume_designers_eras p:hasEras ?eras .
  ?costume_designers a :Costume_Designers .
  ?costume_designers_eras p:hasCostume_Designers ?costume_designers .
  ?costume_designers p:name ?name .
  ?eras p:era_name ?era_name .
} }
  collective: { SELECT ?era_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasEras ?child ; p:hasCostume_Designers ?parent . } GROUP BY ?child }
  ?child p:era_name ?era_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Costume_Designers } }
  FILTER(?nf = ?total)
} }
}
